{
  "name": "belt",
  "version": "0.1.0",
  "private": true,
  "description": "TypeScript utility library with runtime type validation, state management, and common helpers",
  "repository": {
    "type": "git",
    "url": "https://github.com/antoniopresto/belt"
  },
  "author": "@antoniopresto <antoniopresto@gmail.com>",
  "packageManager": "pnpm@9.14.2",
  "engines": {
    "node": ">=20.0.0"
  },
  "scripts": {
    "build": "turbo run build",
    "dev": "turbo run dev",
    "lint": "biome check .",
    "lint:fix": "biome check --write .",
    "format": "biome format --write .",
    "test": "turbo run test",
    "typecheck": "turbo run typecheck",
    "clean": "turbo run clean && rm -rf node_modules",
    "prepare": "husky"
  },
  "devDependencies": {
    "@biomejs/biome": "^2.3.11",
    "@types/node": "^25.0.3",
    "husky": "9.1.7",
    "turbo": "^2.7.2",
    "typescript": "^5.9.3"
  }
}

{
  "name": "@belt/tools",
  "version": "0.1.0",
  "description": "TypeScript utility library with runtime type validation, state management, and common helpers",
  "type": "module",
  "main": "./dist/index.cjs",
  "module": "./dist/index.js",
  "types": "./dist/index.d.ts",
  "exports": {
    ".": {
      "types": "./dist/index.d.ts",
      "import": "./dist/index.js",
      "require": "./dist/index.cjs"
    }
  },
  "files": [
    "dist",
    "README.md"
  ],
  "scripts": {
    "build": "tsup",
    "dev": "tsup --watch",
    "typecheck": "tsc --noEmit",
    "test": "vitest",
    "test:watch": "vitest --watch",
    "coverage": "vitest --coverage"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/zazcart/tools.git"
  },
  "keywords": [
    "typescript",
    "utilities",
    "validation",
    "state-management",
    "type-safe"
  ],
  "author": "@zazcart",
  "peerDependencies": {
    "react": ">=18.0.0"
  },
  "peerDependenciesMeta": {
    "react": {
      "optional": true
    }
  },
  "dependencies": {
    "date-fns": "^4.1.0",
    "immer": "^11.1.3",
    "lodash": "^4.17.21",
    "lru-cache": "^11.2.4",
    "minimatch": "^10.1.1",
    "typebox": "^1.0.73"
  },
  "devDependencies": {
    "@types/lodash": "^4.17.21",
    "@types/node": "^25.0.3",
    "@types/react": "^19.2.7",
    "tsup": "^8.5.1",
    "typescript": "^5.9.3",
    "vitest": "^4.0.16"
  }
}

import { defineConfig } from "tsup";

export default defineConfig({
	entry: ["src/index.ts"],
	format: ["esm", "cjs"],
	dts: true,
	splitting: false,
	sourcemap: true,
	clean: true,
	external: ["react"],
	treeshake: true,
});

